# React Orders Table Component

## Complete Implementation

```jsx
import React, { useState, useEffect, useCallback } from "react";

// ─── Constants ────────────────────────────────────────────────────────────────
const STATUS_STYLES = {
  completed: { bg: "#d1fae5", color: "#065f46", label: "Completed" },
  pending:   { bg: "#fef3c7", color: "#92400e", label: "Pending"   },
  cancelled: { bg: "#fee2e2", color: "#991b1b", label: "Cancelled" },
  default:   { bg: "#e5e7eb", color: "#374151", label: "Unknown"   },
};

// ─── API Layer ────────────────────────────────────────────────────────────────
const fetchOrders = async (signal) => {
  const response = await fetch("/api/orders", { signal });

  if (!response.ok) {
    throw new Error(`Server error: ${response.status} ${response.statusText}`);
  }

  return response.json();
};

// ─── Sub-components ───────────────────────────────────────────────────────────

/** Reusable status badge */
const StatusBadge = ({ status }) => {
  const style = STATUS_STYLES[status?.toLowerCase()] ?? STATUS_STYLES.default;
  return (
    <span
      style={{
        backgroundColor: style.bg,
        color: style.color,
        padding: "2px 10px",
        borderRadius: "9999px",
        fontSize: "0.75rem",
        fontWeight: 600,
        textTransform: "capitalize",
      }}
    >
      {style.label}
    </span>
  );
};

/** Skeleton row shown while loading */
const SkeletonRow = () => (
  <tr>
    {Array.from({ length: 5 }).map((_, i) => (
      <td key={i} style={{ padding: "12px 16px" }}>
        <div
          style={{
            height: "14px",
            borderRadius: "4px",
            backgroundColor: "#e5e7eb",
            animation: "pulse 1.5s ease-in-out infinite",
            width: i === 0 ? "60%" : "80%",
          }}
        />
      </td>
    ))}
  </tr>
);

/** Full-width error banner */
const ErrorBanner = ({ message, onRetry }) => (
  <div
    role="alert"
    style={{
      display: "flex",
      alignItems: "center",
      justifyContent: "space-between",
      padding: "12px 16px",
      backgroundColor: "#fee2e2",
      border: "1px solid #fca5a5",
      borderRadius: "8px",
      color: "#991b1b",
      marginBottom: "16px",
    }}
  >
    <span>⚠️ {message}</span>
    <button
      onClick={onRetry}
      style={{
        marginLeft: "16px",
        padding: "6px 14px",
        backgroundColor: "#991b1b",
        color: "#fff",
        border: "none",
        borderRadius: "6px",
        cursor: "pointer",
        fontWeight: 600,
      }}
    >
      Retry
    </button>
  </div>
);

/** Empty state illustration */
const EmptyState = () => (
  <tr>
    <td colSpan={5} style={{ textAlign: "center", padding: "48px 16px", color: "#6b7280" }}>
      <div style={{ fontSize: "2rem" }}>📭</div>
      <p style={{ margin: "8px 0 0", fontWeight: 500 }}>No orders found</p>
    </td>
  </tr>
);

// ─── Custom Hook ──────────────────────────────────────────────────────────────
/**
 * Encapsulates all data-fetching logic so the component stays clean.
 * Returns { orders, status, error, retry }
 */
const useOrders = () => {
  const [orders, setOrders]   = useState([]);
  const [status, setStatus]   = useState("idle");   // idle | loading | success | error
  const [error, setError]     = useState(null);
  const [retryCount, setRetryCount] = useState(0);

  useEffect(() => {
    // AbortController lets us cancel the request if the component unmounts
    const controller = new AbortController();
    let cancelled = false;

    const load = async () => {
      setStatus("loading");
      setError(null);

      try {
        const data = await fetchOrders(controller.signal);

        if (!cancelled) {
          setOrders(data);
          setStatus("success");
        }
      } catch (err) {
        if (err.name === "AbortError") return; // intentional cancellation – ignore

        if (!cancelled) {
          setError(err.message ?? "An unexpected error occurred.");
          setStatus("error");
        }
      }
    };

    load();

    // Cleanup: cancel in-flight request on unmount or re-fetch
    return () => {
      cancelled = true;
      controller.abort();
    };
  }, [retryCount]); // re-run whenever the user clicks "Retry"

  const retry = useCallback(() => setRetryCount((c) => c + 1), []);

  return { orders, status, error, retry };
};

// ─── Main Component ───────────────────────────────────────────────────────────
const OrdersTable = () => {
  const { orders, status, error, retry } = useOrders();

  const isLoading = status === "loading" || status === "idle";
  const isError   = status === "error";
  const isEmpty   = status === "success" && orders.length === 0;

  return (
    <>
      {/* Keyframe animation injected once */}
      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50%       { opacity: 0.4; }
        }
      `}</style>

      <div style={{ fontFamily: "system-ui, sans-serif", padding: "24px", maxWidth: "900px", margin: "0 auto" }}>

        {/* ── Header ── */}
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: "16px" }}>
          <h1 style={{ margin: 0, fontSize: "1.5rem", fontWeight: 700 }}>Orders</h1>
          {status === "success" && (
            <span style={{ fontSize: "0.875rem", color: "#6b7280" }}>
              {orders.length} order{orders.length !== 1 ? "s" : ""}
            </span>
          )}
        </div>

        {/* ── Error Banner ── */}
        {isError && <ErrorBanner message={error} onRetry={retry} />}

        {/* ── Table ── */}
        <div style={{ overflowX: "auto", borderRadius: "8px", border: "1px solid #e5e7eb" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.875rem" }}>

            <thead style={{ backgroundColor: "#f9fafb" }}>
              <tr>
                {["Order ID", "Customer", "Date", "Amount", "Status"].map((heading) => (
                  <th
                    key={heading}
                    style={{
                      padding: "12px 16px",
                      textAlign: "left",
                      fontWeight: 600,
                      color: "#374151",
                      borderBottom: "1px solid #e5e7eb",
                      whiteSpace: "nowrap",
                    }}
                  >
                    {heading}
                  </th>
                ))}
              </tr>
            </thead>

            <tbody>
              {/* Loading skeletons */}
              {isLoading && Array.from({ length: 5 }).map((_, i) => <SkeletonRow key={i} />)}

              {/* Empty state */}
              {isEmpty && <EmptyState />}

              {/* Data rows */}
              {status === "success" &&
                orders.map((order, index) => (
                  <tr
                    key={order.id}
                    style={{
                      backgroundColor: index % 2 === 0 ? "#fff" : "#f9fafb",
                      transition: "background-color 0.15s",
                    }}
                    onMouseEnter={(e) => (e.currentTarget.style.backgroundColor = "#eff6ff")}
                    onMouseLeave={(e) => (e.currentTarget.style.backgroundColor = index % 2 === 0 ? "#fff" : "#f9fafb")}
                  >
                    <td style={{ padding: "12px 16px", color: "#2563eb", fontWeight: 500 }}>
                      #{order.id}
                    </td>
                    <td style={{ padding: "12px 16px", color: "#111827" }}>
                      {order.customerName}
                    </td>
                    <td style={{ padding: "12px 16px", color: "#6b7280" }}>
                      {new Date(order.createdAt).toLocaleDateString("en-US", {
                        year: "numeric", month: "short", day: "numeric",
                      })}
                    </td>
                    <td style={{ padding: "12px 16px", color: "#111827", fontWeight: 500 }}>
                      {new Intl.NumberFormat("en-US", { style: "currency", currency: "USD" }).format(order.amount)}
                    </td>
                    <td style={{ padding: "12px 16px" }}>
                      <StatusBadge status={order.status} />
                    </td>
                  </tr>
                ))}
            </tbody>
          </table>
        </div>
      </div>
    </>
  );
};

export default OrdersTable;
```

---

## How It All Fits Together

```
useOrders (hook)
│
├── status: "idle" ──► "loading" ──► "success"
│                                └──► "error"
│
├── AbortController  →  cancels fetch on unmount
└── retryCount       →  incrementing triggers re-fetch

OrdersTable (component)
│
├── isLoading  →  renders <SkeletonRow × 5>
├── isError    →  renders <ErrorBanner> with retry button
├── isEmpty    →  renders <EmptyState>
└── success    →  renders real data rows
```

### Key design decisions

| Decision | Why |
|---|---|
| `status` enum instead of `isLoading` + `isError` booleans | Prevents impossible states (e.g. loading *and* error simultaneously) |
| `AbortController` | Prevents state updates on unmounted components |
| `retryCount` dependency | Clean way to re-trigger `useEffect` without duplicating logic |
| Skeleton rows (not a spinner) | Reduces layout shift; matches final table structure |
| Separated `fetchOrders` function | Easy to swap for `axios`, `react-query`, or mock in tests |

Here's a complete implementation following all project conventions:

```typescript
// src/components/orders/OrdersTable.tsx

"use client";

import { useQuery } from "@tanstack/react-query";

// ─── Types ────────────────────────────────────────────────────────────────────

interface Order {
  id: string;
  customerName: string;
  status: "pending" | "processing" | "shipped" | "delivered" | "cancelled";
  total: number;
  createdAt: string;
}

// ─── Query key factory (keeps keys consistent across the app) ─────────────────

export const orderKeys = {
  all: ["orders"] as const,
  list: () => [...orderKeys.all, "list"] as const,
};

// ─── Fetcher (pure async fn, easy to unit-test in isolation) ──────────────────

async function fetchOrders(): Promise<Order[]> {
  const response = await fetch("/api/orders");

  if (!response.ok) {
    throw new Error(`Failed to fetch orders: ${response.statusText}`);
  }

  return response.json();
}

// ─── Sub-components ───────────────────────────────────────────────────────────

const STATUS_STYLES: Record<Order["status"], string> = {
  pending:    "bg-yellow-100 text-yellow-800",
  processing: "bg-blue-100   text-blue-800",
  shipped:    "bg-purple-100 text-purple-800",
  delivered:  "bg-green-100  text-green-800",
  cancelled:  "bg-red-100    text-red-800",
};

function StatusBadge({ status }: { status: Order["status"] }) {
  return (
    <span
      className={`inline-flex items-center rounded-full px-2.5 py-0.5 text-xs font-medium capitalize ${STATUS_STYLES[status]}`}
    >
      {status}
    </span>
  );
}

function SkeletonRow() {
  return (
    <tr className="animate-pulse">
      {Array.from({ length: 4 }).map((_, i) => (
        <td key={i} className="px-6 py-4">
          <div className="h-4 rounded bg-gray-200" />
        </td>
      ))}
    </tr>
  );
}

function ErrorMessage({ message }: { message: string }) {
  return (
    <div
      role="alert"
      className="rounded-lg border border-red-200 bg-red-50 p-4 text-sm text-red-700"
    >
      <span className="font-semibold">Error loading orders: </span>
      {message}
    </div>
  );
}

// ─── Main component ───────────────────────────────────────────────────────────

export function OrdersTable() {
  const {
    data: orders,
    isLoading,
    isError,
    error,
    refetch,
    isFetching,
  } = useQuery({
    queryKey: orderKeys.list(),
    queryFn: fetchOrders,
    staleTime: 30_000, // treat data as fresh for 30 s before a background refetch
  });

  // ── Error state ─────────────────────────────────────────────────────────────
  if (isError) {
    return (
      <div className="space-y-3">
        <ErrorMessage message={error instanceof Error ? error.message : "Unknown error"} />
        <button
          type="button"
          onClick={(_e: React.MouseEvent<HTMLButtonElement>) => refetch()}
          className="rounded-md bg-red-600 px-4 py-2 text-sm font-medium text-white hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-red-500 focus:ring-offset-2"
          aria-label="Retry loading orders"
        >
          Retry
        </button>
      </div>
    );
  }

  // ── Render ──────────────────────────────────────────────────────────────────
  return (
    <div className="space-y-4">
      {/* Header row */}
      <div className="flex items-center justify-between">
        <h2 className="text-lg font-semibold text-gray-900">Orders</h2>

        {/* Subtle spinner shown during background refetches (not initial load) */}
        {isFetching && !isLoading && (
          <span className="text-sm text-gray-500" aria-live="polite">
            Refreshing…
          </span>
        )}
      </div>

      {/* Table */}
      <div className="overflow-hidden rounded-lg border border-gray-200 shadow-sm">
        <table className="min-w-full divide-y divide-gray-200">
          <thead className="bg-gray-50">
            <tr>
              {["Order ID", "Customer", "Status", "Total"].map((heading) => (
                <th
                  key={heading}
                  scope="col"
                  className="px-6 py-3 text-left text-xs font-medium uppercase tracking-wider text-gray-500"
                >
                  {heading}
                </th>
              ))}
            </tr>
          </thead>

          <tbody className="divide-y divide-gray-100 bg-white">
            {/* Loading state: skeleton rows instead of a spinner so layout doesn't jump */}
            {isLoading &&
              Array.from({ length: 5 }).map((_, i) => <SkeletonRow key={i} />)}

            {/* Empty state */}
            {!isLoading && orders?.length === 0 && (
              <tr>
                <td
                  colSpan={4}
                  className="px-6 py-10 text-center text-sm text-gray-500"
                >
                  No orders found.
                </td>
              </tr>
            )}

            {/* Data rows */}
            {orders?.map((order) => (
              <tr key={order.id} className="hover:bg-gray-50">
                <td className="whitespace-nowrap px-6 py-4 font-mono text-sm text-gray-900">
                  {order.id}
                </td>
                <td className="whitespace-nowrap px-6 py-4 text-sm text-gray-700">
                  {order.customerName}
                </td>
                <td className="whitespace-nowrap px-6 py-4">
                  <StatusBadge status={order.status} />
                </td>
                <td className="whitespace-nowrap px-6 py-4 text-sm text-gray-700">
                  {new Intl.NumberFormat("en-US", {
                    style: "currency",
                    currency: "USD",
                  }).format(order.total)}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
```

---

## Key decisions and why

### State management
`useQuery` owns all server state — no `useState`/`useEffect` pair for fetching, per project convention. The query key factory (`orderKeys`) lives alongside the component but can be imported by mutations or other queries that need to invalidate this list later.

### Loading state: skeleton rows, not a spinner
Skeleton rows that match the real table structure prevent layout shift when data arrives. A secondary `isFetching && !isLoading` indicator handles background refetches without re-showing the full skeleton.

### Three distinct states handled explicitly

| State | What renders |
|---|---|
| `isLoading` | 5 skeleton rows |
| `isError` | Inline error message + typed retry button |
| `orders.length === 0` | Empty-state cell spanning all columns |

### Typed event handler
The retry button uses `React.MouseEvent<HTMLButtonElement>` (the parameter is prefixed `_e` since it's unused, which satisfies the linter without an `any`).

### Accessibility
- `<th scope="col">` on every header
- `role="alert"` on the error message so screen readers announce it immediately
- `aria-live="polite"` on the background-refresh indicator
- `aria-label` on the retry button (icon-free buttons still need explicit labels per the a11y audit rules)

### What's intentionally excluded
- No custom CSS — all styling is Tailwind utility classes
- No `<img>` tags — no images needed here
- No Redux — retired per ADR-007

I'll build this using the project's established patterns. Let me call out each decision as I go.

## The Component

```tsx
// src/components/orders/OrdersTable.tsx
"use client";

import { useQuery } from "@tanstack/react-query";
import Image from "next/image";

// ─── Types ────────────────────────────────────────────────────────────────────

interface Order {
  id: string;
  customerName: string;
  status: "pending" | "processing" | "shipped" | "delivered" | "cancelled";
  total: number;
  createdAt: string;
  avatarUrl?: string;
}

interface OrdersApiResponse {
  orders: Order[];
}

// ─── Fetcher ──────────────────────────────────────────────────────────────────

// Kept outside the component so TanStack Query can share/cache it across
// any component that uses the same queryKey.
async function fetchOrders(): Promise<Order[]> {
  const response = await fetch("/api/orders");

  if (!response.ok) {
    // Throwing here lets TanStack Query populate `error` automatically.
    throw new Error(`Failed to fetch orders: ${response.statusText}`);
  }

  const data: OrdersApiResponse = await response.json();
  return data.orders;
}

// ─── Status badge ─────────────────────────────────────────────────────────────

const STATUS_STYLES: Record<Order["status"], string> = {
  pending:    "bg-yellow-100 text-yellow-800",
  processing: "bg-blue-100   text-blue-800",
  shipped:    "bg-purple-100 text-purple-800",
  delivered:  "bg-green-100  text-green-800",
  cancelled:  "bg-red-100    text-red-800",
};

function StatusBadge({ status }: { status: Order["status"] }) {
  return (
    // [f004] Descriptive text content satisfies aria requirements.
    // [f005] Tailwind only — no custom CSS.
    <span
      className={`inline-flex items-center rounded-full px-2.5 py-0.5 text-xs font-medium capitalize ${STATUS_STYLES[status]}`}
    >
      {status}
    </span>
  );
}

// ─── Skeleton loader ──────────────────────────────────────────────────────────

// A dedicated skeleton keeps the loading branch readable and avoids
// layout shift when real data arrives.
function OrdersTableSkeleton() {
  return (
    // [f004] role="status" + aria-label announces loading to screen readers.
    <div role="status" aria-label="Loading orders">
      <div className="animate-pulse space-y-3">
        {/* Header placeholder */}
        <div className="h-10 rounded-md bg-gray-200" />
        {/* Row placeholders */}
        {Array.from({ length: 5 }).map((_, i) => (
          <div key={i} className="h-14 rounded-md bg-gray-100" />
        ))}
      </div>
      <span className="sr-only">Loading orders…</span>
    </div>
  );
}

// ─── Error state ──────────────────────────────────────────────────────────────

function OrdersTableError({ message }: { message: string }) {
  return (
    // [f004] role="alert" surfaces the error to assistive technology immediately.
    <div
      role="alert"
      className="rounded-md border border-red-200 bg-red-50 p-4 text-sm text-red-700"
    >
      <p className="font-semibold">Could not load orders</p>
      <p className="mt-1 text-red-600">{message}</p>
    </div>
  );
}

// ─── Empty state ──────────────────────────────────────────────────────────────

function OrdersTableEmpty() {
  return (
    <div className="py-12 text-center text-sm text-gray-500">
      No orders found.
    </div>
  );
}

// ─── Main component ───────────────────────────────────────────────────────────

export function OrdersTable() {
  // [f001] TanStack Query owns all server state — no useState/useEffect here.
  // [f002] No Redux; this is the approved pattern post-ADR-007.
  const {
    data: orders,
    isLoading,
    isError,
    error,
  } = useQuery<Order[], Error>({
    queryKey: ["orders"],          // Cache key — refetch is automatic on stale.
    queryFn: fetchOrders,
    staleTime: 30_000,             // Treat data as fresh for 30 s.
    retry: 2,                      // Retry transient failures before showing error.
  });

  // ── Render branches ────────────────────────────────────────────────────────

  if (isLoading) return <OrdersTableSkeleton />;

  if (isError) {
    return <OrdersTableError message={error.message} />;
  }

  if (!orders || orders.length === 0) return <OrdersTableEmpty />;

  // ── Happy path ─────────────────────────────────────────────────────────────

  return (
    // Outer wrapper clips the table so rounded corners work on all browsers.
    <div className="overflow-hidden rounded-lg border border-gray-200 shadow-sm">
      <table className="min-w-full divide-y divide-gray-200">
        <thead className="bg-gray-50">
          <tr>
            {["Order", "Customer", "Status", "Total", "Date"].map((heading) => (
              <th
                key={heading}
                scope="col"
                // [f004] scope="col" is the correct semantic for column headers.
                className="px-6 py-3 text-left text-xs font-medium uppercase tracking-wider text-gray-500"
              >
                {heading}
              </th>
            ))}
          </tr>
        </thead>

        <tbody className="divide-y divide-gray-100 bg-white">
          {orders.map((order) => (
            <tr
              key={order.id}
              className="transition-colors hover:bg-gray-50"
            >
              {/* Order ID */}
              <td className="whitespace-nowrap px-6 py-4 text-sm font-mono text-gray-900">
                #{order.id}
              </td>

              {/* Customer — optional avatar + name */}
              <td className="whitespace-nowrap px-6 py-4">
                <div className="flex items-center gap-3">
                  {order.avatarUrl && (
                    // [f008] next/image required for production assets.
                    // [f004] alt text describes the image meaningfully.
                    <Image
                      src={order.avatarUrl}
                      alt={`Avatar for ${order.customerName}`}
                      width={32}
                      height={32}
                      className="rounded-full object-cover"
                    />
                  )}
                  <span className="text-sm text-gray-900">
                    {order.customerName}
                  </span>
                </div>
              </td>

              {/* Status */}
              <td className="whitespace-nowrap px-6 py-4">
                <StatusBadge status={order.status} />
              </td>

              {/* Total */}
              <td className="whitespace-nowrap px-6 py-4 text-sm text-gray-900">
                {new Intl.NumberFormat("en-US", {
                  style: "currency",
                  currency: "USD",
                }).format(order.total)}
              </td>

              {/* Date */}
              <td className="whitespace-nowrap px-6 py-4 text-sm text-gray-500">
                {new Intl.DateTimeFormat("en-US", {
                  dateStyle: "medium",
                }).format(new Date(order.createdAt))}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
```

## Query Client Setup (if not already in place)

```tsx
// src/app/providers.tsx  — wrap your root layout with this
"use client";

import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { useState, type ReactNode } from "react";

export function Providers({ children }: { children: ReactNode }) {
  // useState ensures each browser session gets its own client,
  // preventing state leaking between users in SSR environments.
  const [queryClient] = useState(
    () =>
      new QueryClient({
        defaultOptions: {
          queries: {
            staleTime: 30_000,
            retry: 2,
          },
        },
      }),
  );

  return (
    <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
  );
}
```

```tsx
// src/app/layout.tsx
import { Providers } from "./providers";

export default function RootLayout({ children }: { children: React.ReactNode }) {
  return (
    <html lang="en">
      <body>
        <Providers>{children}</Providers>
      </body>
    </html>
  );
}
