  /** Overrides the default headline copy */
  headline?: string;
  /** Overrides the default sub-copy */
  subheading?: string;
}

export default function HeroImage({
  headline = "Welcome to Acme",
  subheading = "Build something great.",
}: HeroImageProps) {
  return (
    /*
     * position: relative  → required so the absolutely-positioned
     *                        <Image fill> knows its containing block.
     * aspect-[2/1]        → mirrors the 2400×1200 source ratio so the
     *                        container reserves the right amount of space
     *                        before the image loads (prevents CLS).
     * max-h-[600px]       → stops the hero growing too tall on wide screens.
     */
    <section className="relative w-full aspect-[2/1] max-h-[600px] overflow-hidden">
      <Image
        src={heroSrc}          // static import carries width/height metadata
        alt="A wide hero shot showing our product in action"
        /*
         * fill        → stretches to the parent; lets CSS control the size
         *               instead of hard-coding px values in JSX.
         * sizes       → tells the browser which rendered width to expect at
         *               each viewport so it downloads the smallest adequate
         *               variant. Adjust breakpoints to match your layout.
         */
        fill
        sizes="100vw"
        /*
         * priority    → marks this image as LCP-critical.
         *               Next.js emits a <link rel="preload"> and skips
         *               lazy-loading. Only use on above-the-fold images.
         */
        priority
        /*
         * object-cover keeps the image filling the box without distortion,
         * cropping edges on narrow viewports (same as CSS background-size).
         */
        className="object-cover object-center"
        /*
         * quality 85 is a good balance: visually lossless for photos,
         * noticeably smaller file than the default 75 for AVIF/WebP.
         */
        quality={85}
      />

      {/* Overlay + copy sit above the image in the stacking context */}
      <div className="relative z-10 flex h-full flex-col items-center justify-center gap-4 bg-black/40 px-4 text-center text-white">
