        src={src}
        alt={alt}               // f004 – descriptive alt satisfies a11y audit
        fill                    // fills the positioned parent; no layout shift
        sizes="100vw"           // hero is always full-viewport-width
        priority                // LCP element – skip lazy-loading, preload it
        quality={85}            // good visual fidelity; avoids bloating the
                                // already-large source
        // next/image + formats:["avif","webp"] in next.config.js means the
        // browser receives AVIF/WebP, not the 1.2 MB PNG  (f007 – bundle safe
        // because the image is never imported into JS)
      />
    </div>
  );
}
